   133→export function loadRaceTextures(race: Race, texManager: TextureManager): RaceTextures {
   134→  const paths = raceTexturePaths(race);
   135→  const tex: any = {};
   136→  for (const [key, path] of Object.entries(paths)) {
   137→    tex[key] = texManager.load(path);
   138→  }
   139→  tex.escBtnBgTiled = texManager.loadRepeat(paths.escBtnBg);
   140→  tex.escMenuBgTiled = texManager.loadRepeat(paths.escMenuBg);
   141→  tex.tooltipBgTiled = texManager.loadRepeat(paths.tooltipBg);
   142→  tex.glueBgTiled = texManager.loadRepeat(paths.glueBg);
   143→  tex.glueBgDownTiled = texManager.loadRepeat(paths.glueBgDown);
   144→  tex.glueBgDisabledTiled = texManager.loadRepeat(paths.glueBgDisabled);
   145→  return tex as RaceTextures;
   146→}
   147→
   148→export function preloadAllRaces(texManager: TextureManager) {
   149→  RACES.forEach(r => {
   150→    const paths = raceTexturePaths(r);
   151→    Object.values(paths).forEach(p => texManager.load(p));
   152→  });
   153→}
