    32→function compileShader(gl: WebGLRenderingContext, type: number, src: string): WebGLShader | null {
    33→  const shader = gl.createShader(type);
    34→  if (!shader) return null;
    35→  gl.shaderSource(shader, src);
    36→  gl.compileShader(shader);
    37→  if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
    38→    console.error('Top HUD shader compile failed:', gl.getShaderInfoLog(shader));
    39→    gl.deleteShader(shader);
    40→    return null;
    41→  }
    42→  return shader;
    43→}
